code_examples.insecureCode:
// ❌ Insecure: Trusts the provided ID blindly
app.get('/api/invoice/:id', (req, res) => {
  const invoice = DB.findInvoice(req.params.id);
  // Error: No check to see if this invoice belongs to req.user.id!
  res.json(invoice);
});

code_examples.secureCode:
// ✓ Secure: Enforces ownership at the database level
app.get('/api/invoice/:id', (req, res) => {
  const invoice = DB.findInvoice({
    id: req.params.id,
    ownerId: req.user.id // Critical: Context-aware filtering
  });

  if (!invoice) return res.status(404).json({ error: 'Invoice not found or access denied.' });
  res.json(invoice);
});
